<?php
 namespace WPAICG\Chat\Storage; use wpdb; if (!defined('ABSPATH')) { exit; } class LogQueryHelper { private $table_name; public function __construct($table_name) { $this->table_name = $table_name; } public function build_conversation_query_parts( array $filters = [], string $orderby = 'updated_at', string $order = 'DESC', int $limit = 50, int $offset = 0, bool $select_messages = false ): array { global $wpdb; $where_clauses = ['1=1']; $params = []; $join_sql = ''; $select_fields = [ "{$this->table_name}.id", "{$this->table_name}.bot_id", "{$this->table_name}.user_id", "{$this->table_name}.session_id", "{$this->table_name}.conversation_uuid", "{$this->table_name}.is_guest", "{$this->table_name}.module", "{$this->table_name}.message_count", "{$this->table_name}.first_message_ts", "{$this->table_name}.last_message_ts", "{$this->table_name}.ip_address", "{$this->table_name}.user_wp_role", "{$this->table_name}.created_at", "{$this->table_name}.updated_at" ]; if ($select_messages) { $select_fields[] = "{$this->table_name}.messages"; } if (isset($filters['bot_id'])) { $bot_filter_value = trim((string)$filters['bot_id']); if ($bot_filter_value === '' || $bot_filter_value === '0') { $where_clauses[] = "{$this->table_name}.bot_id IS NULL"; } else { $where_clauses[] = "{$this->table_name}.bot_id = %d"; $params[] = absint($bot_filter_value); } } if (isset($filters['user_id'])) { if ($filters['user_id'] === null || $filters['user_id'] === 0) { $where_clauses[] = "{$this->table_name}.user_id IS NULL"; } else { $where_clauses[] = "{$this->table_name}.user_id = %d"; $params[] = absint($filters['user_id']); } } if (!empty($filters['session_id'])) { $where_clauses[] = "{$this->table_name}.session_id = %s"; $params[] = sanitize_text_field($filters['session_id']); } if (!empty($filters['conversation_uuid'])) { $where_clauses[] = "{$this->table_name}.conversation_uuid = %s"; $params[] = sanitize_key($filters['conversation_uuid']); } if (!empty($filters['module'])) { $module_filter = sanitize_key($filters['module']); if ($module_filter === 'chatbot') { $where_clauses[] = "({$this->table_name}.module IS NULL OR {$this->table_name}.module = '')"; } else { $where_clauses[] = "{$this->table_name}.module = %s"; $params[] = $module_filter; } } if (!empty($filters['start_ts'])) { $where_clauses[] = "{$this->table_name}.last_message_ts >= %d"; $params[] = absint($filters['start_ts']); } if (!empty($filters['end_ts'])) { $where_clauses[] = "{$this->table_name}.last_message_ts <= %d"; $params[] = absint($filters['end_ts']); } $search_value = isset($filters['search']) ? trim((string) $filters['search']) : ''; if ($search_value !== '') { $join_sql = " LEFT JOIN {$wpdb->users} AS u ON u.ID = {$this->table_name}.user_id "; $select_fields[] = "u.display_name as user_display_name"; $likeVal = '%' . $wpdb->esc_like($search_value) . '%'; $where_clauses[] = "( (u.display_name IS NOT NULL AND u.display_name LIKE %s) OR ({$this->table_name}.is_guest = 1 AND {$this->table_name}.session_id LIKE %s) OR {$this->table_name}.messages LIKE %s )"; $params[] = $likeVal; $params[] = $likeVal; $params[] = $likeVal; } else { if (!empty($filters['user_name'])) { $join_sql = " LEFT JOIN {$wpdb->users} AS u ON u.ID = {$this->table_name}.user_id "; $select_fields[] = "u.display_name as user_display_name"; $where_clauses[] = "( (u.display_name IS NOT NULL AND u.display_name LIKE %s) OR ({$this->table_name}.is_guest = 1 AND {$this->table_name}.session_id LIKE %s) )"; $likeVal = '%' . $wpdb->esc_like($filters['user_name']) . '%'; $params[] = $likeVal; $params[] = $likeVal; } else { $select_fields[] = "NULL as user_display_name"; } if (!empty($filters['message_like'])) { $where_clauses[] = "{$this->table_name}.messages LIKE %s"; $likeVal = '%' . $wpdb->esc_like($filters['message_like']) . '%'; $params[] = $likeVal; } } $valid_orderby = ['id', 'bot_id', 'user_id', 'session_id', 'conversation_uuid', 'message_count', 'first_message_ts', 'last_message_ts', 'created_at', 'updated_at']; if ($join_sql) { $valid_orderby[] = 'user_display_name'; } $orderby_final = 'last_message_ts'; if (in_array(strtolower($orderby), $valid_orderby)) { if ($orderby === 'user_display_name' && $join_sql) { $orderby_final = 'u.display_name'; } else { $orderby_final = $this->table_name . '.' . strtolower($orderby); } } $order_final = in_array(strtoupper($order), ['ASC','DESC']) ? strtoupper($order) : 'DESC'; $limit_sql = ''; if ($limit > 0) { $limit_sql = $wpdb->prepare('LIMIT %d OFFSET %d', absint($limit), absint($offset)); } $where_sql = implode(' AND ', $where_clauses); $select_sql = implode(', ', $select_fields); return [ 'select_sql' => $select_sql, 'where_sql' => $where_sql, 'params' => $params, 'orderby' => $orderby_final, 'order' => $order_final, 'limit_sql' => $limit_sql, 'join_sql' => $join_sql, ]; } public function build_conversation_count_query_parts(array $filters = []): array { global $wpdb; $query_parts = $this->build_conversation_query_parts($filters, '', '', 0, 0, false); $count_sql = "SELECT COUNT(*)
                      FROM {$this->table_name}
                      {$query_parts['join_sql']}
                      WHERE {$query_parts['where_sql']}"; return [ 'count_sql' => $count_sql, 'params' => $query_parts['params'], ]; } public function build_message_query_parts(array $filters = [], string $orderby = 'id', string $order = 'ASC', int $limit = 100, int $offset = 0): array { return $this->build_conversation_query_parts($filters, $orderby, $order, $limit, $offset, true); } } 